// --- Server-Side Simulation (runs in same file for demo, but represents server authority) ---
const ServerSimulation = (() => {
    const SERVER_TICK_RATE = 60;
    const MAX_SPEED = 300; // pixels per second
    const ACCELERATION = 150; // pixels per second^2
    const DECELERATION = 200; // pixels per second^2
    const TRACK_LENGTH = 5000;
    const MAX_ACCEPTABLE_DELTA = 50; // ms - max delta time we accept
    const MIN_ACCEPTABLE_DELTA = 5; // ms - min delta time we accept
    const POSITION_TOLERANCE = 50; // pixels of drift allowed before correction
    const SPEED_HACK_THRESHOLD = 1.15; // 15% tolerance for timing discrepancies
    const MAX_VIOLATIONS = 10;

    const players = {};
    let serverTime = performance.now();
    let lastServerTick = performance.now();

    function registerPlayer(id) {
        players[id] = {
            x: 0,
            y: 300,
            velocityX: 0,
            velocityY: 0,
            input: { up: false, down: false, left: false, right: false },
            lastInputSequence: 0,
            serverX: 0,
            serverY: 0,
            lastUpdateTime: performance.now(),
            totalDistanceServer: 0,
            totalDistanceClient: 0,
            violations: 0,
            banned: false,
            wallClockStart: performance.now(),
            gameTimeAccumulated: 0,
            lastClientTimestamp: performance.now(),
            inputHistory: [],
            finished: false,
            finishTime: null
        };
        return players[id];
    }

    function receiveClientInput(playerId, inputData) {
        const player = players[playerId];
        if (!player || player.banned || player.finished) return null;

        const now = performance.now();
        const clientDelta = inputData.deltaTime;
        const clientTimestamp = inputData.timestamp;

        // --- ANTI-CHEAT: Validate delta time bounds ---
        if (clientDelta > MAX_ACCEPTABLE_DELTA || clientDelta < MIN_ACCEPTABLE_DELTA) {
            // Ignore suspicious delta times - use server-calculated delta instead
            player.violations++;
            console.warn(`[Server] Player ${playerId}: Invalid delta ${clientDelta.toFixed(1)}ms (violation ${player.violations}/${MAX_VIOLATIONS})`);
            if (player.violations >= MAX_VIOLATIONS) {
                player.banned = true;
                return { banned: true, reason: "Speed manipulation detected" };
            }
        }

        // --- ANTI-CHEAT: Wall clock validation ---
        // Compare accumulated game time vs real wall clock time
        const wallClockElapsed = now - player.wallClockStart;
        player.gameTimeAccumulated += clientDelta;

        if (player.gameTimeAccumulated > wallClockElapsed * SPEED_HACK_THRESHOLD) {
            player.violations += 2;
            console.warn(`[Server] Player ${playerId}: Game time ${player.gameTimeAccumulated.toFixed(0)}ms exceeds wall clock ${wallClockElapsed.toFixed(0)}ms (violation ${player.violations}/${MAX_VIOLATIONS})`);
            if (player.violations >= MAX_VIOLATIONS) {
                player.banned = true;
                return { banned: true, reason: "Time manipulation detected" };
            }
            // Reset accumulated time to wall clock
            player.gameTimeAccumulated = wallClockElapsed;
        }

        // --- ANTI-CHEAT: Use SERVER-calculated delta, not client-reported ---
        const serverDelta = Math.min(now - player.lastUpdateTime, MAX_ACCEPTABLE_DELTA);
        player.lastUpdateTime = now;

        // Store input
        player.input = inputData.keys;
        player.lastInputSequence = inputData.sequence;

        // --- SERVER AUTHORITATIVE PHYSICS ---
        const dt = serverDelta / 1000; // Use server delta, NOT client delta

        // Apply acceleration based on input
        let targetVX = 0;
        let targetVY = 0;

        if (player.input.right) targetVX = MAX_SPEED;
        if (player.input.left) targetVX = -MAX_SPEED;
        if (player.input.down) targetVY = MAX_SPEED;
        if (player.input.up) targetVY = -MAX_SPEED;

        // Smooth acceleration/deceleration
        if (targetVX !== 0) {
            player.velocityX += Math.sign(targetVX - player.velocityX) * ACCELERATION * dt;
            player.velocityX = Math.max(-MAX_SPEED, Math.min(MAX_SPEED, player.velocityX));
        } else {
            if (Math.abs(player.velocityX) < DECELERATION * dt) {
                player.velocityX = 0;
            } else {
                player.velocityX -= Math.sign(player.velocityX) * DECELERATION * dt;
            }
        }

        if (targetVY !== 0) {
            player.velocityY += Math.sign(targetVY - player.velocityY) * ACCELERATION * dt;
            player.velocityY = Math.max(-MAX_SPEED, Math.min(MAX_SPEED, player.velocityY));
        } else {
            if (Math.abs(player.velocityY) < DECELERATION * dt) {
                player.velocityY = 0;
            } else {
                player.velocityY -= Math.sign(player.velocityY) * DECELERATION * dt;
            }
        }

        const oldX = player.serverX;
        const oldY = player.serverY;

        player.serverX += player.velocityX * dt;
        player.serverY += player.velocityY * dt;

        // Track boundaries
        player.serverY = Math.max(50, Math.min(550, player.serverY));
        player.serverX = Math.max(0, player.serverX);

        const distThisFrame = Math.sqrt(
            (player.serverX - oldX) ** 2 + (player.serverY - oldY) ** 2
        );
        player.totalDistanceServer += distThisFrame;

        // --- ANTI-CHEAT: Validate client-reported distance ---
        if (inputData.clientDistance !== undefined) {
            player.totalDistanceClient = inputData.clientDistance;
            if (player.totalDistanceClient > player.totalDistanceServer * SPEED_HACK_THRESHOLD + POSITION_TOLERANCE) {
                player.violations++;
                console.warn(`[Server] Player ${playerId}: Client distance ${player.totalDistanceClient.toFixed(0)} exceeds server ${player.totalDistanceServer.toFixed(0)} (violation ${player.violations}/${MAX_VIOLATIONS})`);
                if (player.violations >= MAX_VIOLATIONS) {
                    player.banned = true;
                    return { banned: true, reason: "Distance manipulation detected" };
                }
            }
        }

        // Check finish
        if (player.serverX >= TRACK_LENGTH && !player.finished) {
            player.finished = true;
            player.finishTime = wallClockElapsed;
        }

        // Return authoritative state
        return {
            x: player.serverX,
            y: player.serverY,
            vx: player.velocityX,
            vy: player.velocityY,
            sequence: inputData.sequence,
            serverTime: now,
            totalDistance: player.totalDistanceServer,
            violations: player.violations,
            finished: player.finished,
            finishTime: player.finishTime,
            banned: false
        };
    }

    function getPlayerState(playerId) {
        return players[playerId];
    }

    return { registerPlayer, receiveClientInput, getPlayerState, TRACK_LENGTH, MAX_SPEED };
})();


