(function () {
    // --- Setup Canvas ---
    const canvas = document.createElement('canvas');
    canvas.width = 900;
    canvas.height = 600;
    canvas.style.border = '2px solid #333';
    canvas.style.display = 'block';
    canvas.style.margin = '10px auto';
    canvas.style.background = '#1a1a2e';
    document.body.style.background = '#0f0f23';
    document.body.style.fontFamily = 'monospace';
    document.body.style.color = '#eee';

    const title = document.createElement('h1');
    title.textContent = '🏎️ Competitive Racing Game';
    title.style.textAlign = 'center';
    title.style.color = '#e94560';
    document.body.appendChild(title);

    const info = document.createElement('div');
    info.style.textAlign = 'center';
    info.style.marginBottom = '10px';
    info.innerHTML = 'Arrow Keys / WASD to move | Race to the finish line! | <span style="color:#e94560">Server-authoritative physics prevents speed hacks</span>';
    document.body.appendChild(info);

    document.body.appendChild(canvas);

    const statusDiv = document.createElement('div');
    statusDiv.id = 'status';
    statusDiv.style.textAlign = 'center';
    statusDiv.style.fontSize = '14px';
    statusDiv.style.marginTop = '10px';
    document.body.appendChild(statusDiv);

    const ctx = canvas.getContext('2d');

    // --- Game State ---
    const PLAYER_ID = 'player1';
    const GAME_LOOP_INTERVAL = 16; // ~60fps

    ServerSimulation.registerPlayer(PLAYER_ID);

    const gameState = {
        // Client-side predicted position
        x: 0,
        y: 300,
        velocityX: 0,
        velocityY: 0,

        // Server-confirmed position
        serverX: 0,
        serverY: 300,

        // Input state
        keys: { up: false, down: false, left: false, right: false },

        // Timing
        lastFrameTime: performance.now(),
        inputSequence: 0,

        // Stats
        clientDistance: 0,
        serverDistance: 0,
        violations: 0,
        fps: 0,
        frameCount: 0,
        fpsTimer: performance.now(),
        finished: false,
        finishTime: null,
        banned: false,
        banReason: '',

        // Camera
        cameraX: 0,

        // Input history for reconciliation
        pendingInputs: [],

        // Particles
        particles: [],

        // Track
        trackLength: ServerSimulation.TRACK_LENGTH,
        maxSpeed: ServerSimulation.MAX_SPEED,

        // Opponents (AI)
        opponents: [
            { x: 0, y: 200, vx: 0, color: '#ff6b6b', name: 'Red Racer', finished: false },
            { x: 0, y: 400, vx: 0, color: '#4ecdc4', name: 'Teal Thunder', finished: false },
            { x: 0, y: 500, vx: 0, color: '#ffe66d', name: 'Gold Flash', finished: false }
        ]
    };

    // --- Input Handling ---
    const keyMap = {
        'ArrowUp': 'up', 'KeyW': 'up',
        'ArrowDown': 'down', 'KeyS': 'down',
        'ArrowLeft': 'left', 'KeyA': 'left',
        'ArrowRight': 'right', 'KeyD': 'right'
    };

    document.addEventListener('keydown', (e) => {
        const action = keyMap[e.code];
        if (action) {
            gameState.keys[action] = true;
            e.preventDefault();
        }
    });

    document.addEventListener('keyup', (e) => {
        const action = keyMap[e.code];
        if (action) {
            gameState.keys[action] = false;
            e.preventDefault();
        }
    });

    // --- Client-Side Prediction (for responsiveness) ---
    const ACCELERATION = 150;
    const DECELERATION = 200;

    function clientPredict(dt) {
        let targetVX = 0;
        let targetVY = 0;

        if (gameState.keys.right) targetVX = gameState.maxSpeed;
        if (gameState.keys.left) targetVX = -gameState.maxSpeed;
        if (gameState.keys.down) targetVY = gameState.maxSpeed;
        if (gameState.keys.up) targetVY = -gameState.maxSpeed;

        if (targetVX !== 0) {
            gameState.velocityX += Math.sign(targetVX - gameState.velocityX) * ACCELERATION * dt;
            gameState.velocityX = Math.max(-gameState.maxSpeed, Math.min(gameState.maxSpeed, gameState.velocityX));
        } else {
            if (Math.abs(gameState.velocityX) < DECELERATION * dt) {
                gameState.velocityX = 0;
            } else {
                gameState.velocityX -= Math.sign(gameState.velocityX) * DECELERATION * dt;
            }
        }

        if (targetVY !== 0) {
            gameState.velocityY += Math.sign(targetVY - gameState.velocityY) * ACCELERATION * dt;
            gameState.velocityY = Math.max(-gameState.maxSpeed, Math.min(gameState.maxSpeed, gameState.velocityY));
        } else {
            if (Math.abs(gameState.velocityY) < DECELERATION * dt) {
                gameState.velocityY = 0;
            } else {
                gameState.velocityY -= Math.sign(gameState.velocityY) * DECELERATION * dt;
            }
        }

        const oldX = gameState.x;
        const oldY = gameState.y;

        gameState.x += gameState.velocityX * dt;
        gameState.y += gameState.velocityY * dt;

        gameState.y = Math.max(50, Math.min(550, gameState.y));
        gameState.x = Math.max(0, gameState.x);

        const dist = Math.sqrt((gameState.x - oldX) ** 2 + (gameState.y - oldY) ** 2);
        gameState.clientDistance += dist;
    }

    // --- Server Reconciliation ---
    function reconcileWithServer(serverState) {
        if (serverState.banned) {
            gameState.banned = true;
            gameState.banReason = serverState.reason;
            return;
        }

        gameState.serverX = serverState.x;
        gameState.serverY = serverState.y;
        gameState.serverDistance = serverState.totalDistance;
        gameState.violations = serverState.violations;

        if (serverState.finished) {
            gameState.finished = true;
            gameState.finishTime = serverState.finishTime;
        }

        // Snap client to server position if too far off
        const dx = gameState.x - serverState.x;
        const dy = gameState.y - serverState.y;
        const drift = Math.sqrt(dx * dx + dy * dy);

        if (drift > 30) {
            // Smooth correction
            gameState.x = gameState.x + (serverState.x - gameState.x) * 0.3;
            gameState.y = gameState.y + (serverState.y - gameState.y) * 0.3;
            gameState.velocityX = serverState.vx;
            gameState.velocityY = serverState.vy;
            gameState.clientDistance = serverState.totalDistance;
        }

        // Remove acknowledged inputs
        gameState.pendingInputs = gameState.pendingInputs.filter(
            input => input.sequence > serverState.sequence
        );
    }

    // --- Update Opponents (simple AI) ---
    function updateOpponents(dt) {
        gameState.opponents.forEach((opp, i) => {
            if (opp.finished) return;

            // Simple AI with varying speeds
            const baseSpeed = 120 + i * 30;
            const variation = Math.sin(performance.now() / (1000 + i * 500)) * 40;
            const targetSpeed = baseSpeed + variation;

            opp.vx += (targetSpeed - opp.vx) * dt * 2;
            opp.x += opp.vx * dt;

            // Slight vertical wobble
            opp.y += Math.sin(performance.now() / (800 + i * 200)) * 0.5;
            opp.y = Math.max(50, Math.min(550, opp.y));

            if (opp.x >= gameState.trackLength) {
                opp.finished = true;
            }
        });
    }

    // --- Particles ---
    function spawnParticle(x, y, vx, vy, color, life) {
        if (gameState.particles.length > 200) return;
        gameState.particles.push({ x, y, vx, vy, color, life, maxLife: life, size: 2 + Math.random() * 3 });
    }

    function updateParticles(dt) {
        for (let i = gameState.particles.length - 1; i >= 0; i--) {
            const p = gameState.particles[i];
            p.x += p.vx * dt;
            p.y += p.vy * dt;
            p.life -= dt;
            if (p.life <= 0) {
                gameState.particles.splice(i, 1);
            }
        }
    }

    // --- Rendering ---
    function render() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        // Camera follows player
        const targetCameraX = gameState.x - 200;
        gameState.cameraX += (targetCameraX - gameState.cameraX) * 0.1;

        ctx.save();
        ctx.translate(-gameState.cameraX, 0);

        // Draw track background
        drawTrack();

        // Draw particles
        gameState.particles.forEach(p => {
            const alpha = p.life / p.maxLife;
            ctx.globalAlpha = alpha;
            ctx.fillStyle = p.color;
            ctx.fillRect(p.x - p.size / 2, p.y - p.size / 2, p.size, p.size);
        });
        ctx.globalAlpha = 1;

        // Draw opponents
        gameState.opponents.forEach(opp => {
            drawCar(opp.x, opp.y, opp.color, opp.name, opp.vx);
        });

        // Draw player
        drawCar(gameState.x, gameState.y, '#e94560', 'YOU', gameState.velocityX);

        // Draw exhaust particles
        if (Math.abs(gameState.velocityX) > 50) {
            for (let i = 0; i < 2; i++) {
                spawnParticle(
                    gameState.x - 20,
                    gameState.y + (Math.random() - 0.5) * 10,
                    -Math.random() * 100 - 50,
                    (Math.random() - 0.5) * 60,
                    Math.random() > 0.5 ? '#ff6b35' : '#ffaa00',
                    0.3 + Math.random() * 0.3
                );
            }
        }

        // Draw finish line
        drawFinishLine();

        ctx.restore();

        // Draw HUD
        drawHUD();

        // Draw ban overlay
        if (gameState.banned) {
            drawBanScreen();
        }

        // Draw finish overlay
        if (gameState.finished && !gameState.banned) {
            drawFinishScreen();
        }
    }

    function drawTrack() {
        // Road
        ctx.fillStyle = '#2d2d44';
        ctx.fillRect(-100, 30, gameState.trackLength + 1200, 540);

        // Lane markings
        ctx.strokeStyle = '#444466';
        ctx.lineWidth = 2;
        ctx.setLineDash([30, 20]);
        for (let lane = 1; lane < 5; lane++) {
            const y = 30 + lane * 108;
            ctx.beginPath();
            ctx.moveTo(-100, y);
            ctx.lineTo(gameState.trackLength + 1100, y);
            ctx.stroke();
        }
        ctx.setLineDash([]);

        // Road edges
        ctx.strokeStyle = '#e94560';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(-100, 30);
        ctx.lineTo(gameState.trackLength + 1100, 30);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(-100, 570);
        ctx.lineTo(gameState.trackLength + 1100, 570);
        ctx.stroke();

        // Distance markers
        ctx.fillStyle = '#666688';
        ctx.font = '12px monospace';
        for (let d = 0; d <= gameState.trackLength; d += 500) {
            ctx.fillText(`${d}m`, d, 25);
            ctx.strokeStyle = '#333355';
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(d, 30);
            ctx.lineTo(d, 570);
            ctx.stroke();
        }
    }

    function drawCar(x, y, color, name, speed) {
        // Car body
        ctx.fillStyle = color;
        ctx.beginPath();
        ctx.moveTo(x + 25, y);
        ctx.lineTo(x + 15, y - 12);
        ctx.lineTo(x - 5, y - 12);
        ctx.lineTo(x - 20, y - 8);
        ctx.lineTo(x - 20, y + 8);
        ctx.lineTo(x - 5, y + 12);
        ctx.lineTo(x + 15, y + 12);
        ctx.closePath();
        ctx.fill();

        // Windshield
        ctx.fillStyle = '#16213e';
        ctx.fillRect(x + 2, y - 8, 10, 16);

        // Wheels
        ctx.fillStyle = '#111';
        ctx.fillRect(x + 10, y - 15, 8, 4);
        ctx.fillRect(x + 10, y + 11, 8, 4);
        ctx.fillRect(x - 15, y - 15, 8, 4);
        ctx.fillRect(x - 15, y + 11, 8, 4);

        // Speed lines
        if (Math.abs(speed) > 100) {
            ctx.strokeStyle = color;
            ctx.globalAlpha = 0.3;
            ctx.lineWidth = 1;
            for (let i = 0; i < 3; i++) {
                const ly = y - 8 + i * 8;
                const len = Math.abs(speed) / 5;
                ctx.beginPath();
                ctx.moveTo(x - 25, ly);
                ctx.lineTo(x - 25 - len, ly);
                ctx.stroke();
            }
            ctx.globalAlpha = 1;
        }

        // Name tag
        ctx.fillStyle = '#fff';
        ctx.font = 'bold 10px monospace';
        ctx.textAlign = 'center';
        ctx.fillText(name, x, y - 20);
        ctx.textAlign = 'left';
    }

    function drawFinishLine() {
        const fx = gameState.trackLength;
        const squareSize = 15;
        for (let row = 0; row < 36; row++) {
            for (let col = 0; col < 3; col++) {
                ctx.fillStyle = (row + col) % 2 === 0 ? '#fff' : '#111';
                ctx.fillRect(fx + col * squareSize, 30 + row * squareSize, squareSize, squareSize);
            }
        }

        ctx.fillStyle = '#fff';
        ctx.font = 'bold 16px monospace';
        ctx.textAlign = 'center';
        ctx.fillText('FINISH', fx + 22, 22);
        ctx.textAlign = 'left';
    }

    function drawHUD() {
        // Background panel
        ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
        ctx.fillRect(5, 5, 280, 145);
        ctx.strokeStyle = '#e94560';
        ctx.lineWidth = 1;
        ctx.strokeRect(5, 5, 280, 145);

        ctx.fillStyle = '#fff';
        ctx.font = '12px monospace';
        let y = 22;
        const lineHeight = 18;

        ctx.fillText(`FPS: ${gameState.fps}`, 15, y); y += lineHeight;
        ctx.fillText(`Speed: ${Math.abs(gameState.velocityX).toFixed(0)} px/s`, 15, y); y += lineHeight;
        ctx.fillText(`Position: ${gameState.x.toFixed(0)} / ${gameState.trackLength}`, 15, y); y += lineHeight;

        // Progress bar
        const progress = Math.min(gameState.x / gameState.trackLength, 1);
        ctx.fillStyle = '#333';
        ctx.fillRect(15, y - 3, 250, 12);
        ctx.fillStyle = '#e94560';
        ctx.fillRect(15, y - 3, 250 * progress, 12);
        ctx.fillStyle = '#fff';
        ctx.font = '9px monospace';
        ctx.fillText(`${(progress * 100).toFixed(1)}%`, 125, y + 6);
        y += lineHeight;

        ctx.font = '12px monospace';
        ctx.fillStyle = '#4ecdc4';
        ctx.fillText(`Server Dist: ${gameState.serverDistance.toFixed(0)}`, 15, y); y += lineHeight;
        ctx.fillText(`Client Dist: ${gameState.clientDistance.toFixed(0)}`, 15, y); y += lineHeight;

        // Violations indicator
        const violationColor = gameState.violations > 5 ? '#ff0000' : gameState.violations > 2 ? '#ffaa00' : '#00ff00';
        ctx.fillStyle = violationColor;
        ctx.fillText(`Violations: ${gameState.violations}/10`, 15, y);

        // Anti-cheat status panel
        ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
        ctx.fillRect(canvas.width - 285, 5, 280, 65);
        ctx.strokeStyle = '#4ecdc4';
        ctx.strokeRect(canvas.width - 285, 5, 280, 65);

        ctx.fillStyle = '#4ecdc4';
        ctx.font = 'bold 11px monospace';
        ctx.fillText('🛡️ ANTI-CHEAT: SERVER AUTHORITATIVE', canvas.width - 275, 22);
        ctx.font = '10px monospace';
        ctx.fillStyle = '#aaa';
        ctx.fillText('• Server calculates all positions', canvas.width - 275, 38);
        ctx.fillText('• Client delta times are NOT trusted', canvas.width - 275, 52);
        ctx.fillText('• Wall-clock validation active', canvas.width - 275, 66);

        // Minimap
        drawMinimap();
    }

    function drawMinimap() {
        const mx = canvas.width - 285;
        const my = canvas.height - 55;
        const mw = 280;
        const mh = 40;

        ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
        ctx.fillRect(mx, my, mw, mh);
        ctx.strokeStyle = '#666';
        ctx.strokeRect(mx, my, mw, mh);

        // Finish line on minimap
        const finishX = mx + (gameState.trackLength / gameState.trackLength) * (mw - 10);
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(finishX, my);
        ctx.lineTo(finishX, my + mh);
        ctx.stroke();

        // Player dot
        const playerMX = mx + (gameState.x / gameState.trackLength) * (mw - 10);
        ctx.fillStyle = '#e94560';
        ctx.beginPath();
        ctx.arc(playerMX, my + mh / 2, 4, 0, Math.PI * 2);
        ctx.fill();

        // Opponent dots
        gameState.opponents.forEach(opp => {
            const oppMX = mx + (opp.x / gameState.trackLength) * (mw - 10);
            ctx.fillStyle = opp.color;
            ctx.beginPath();
            ctx.arc(oppMX, my + mh / 2, 3, 0, Math.PI * 2);
            ctx.fill();
        });
    }

    function drawBanScreen() {
        ctx.fillStyle = 'rgba(0, 0, 0, 0.85)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#ff0000';
        ctx.font = 'bold 48px monospace';
        ctx.textAlign = 'center';
        ctx.fillText('⛔ BANNED ⛔', canvas.width / 2, canvas.height / 2 - 40);

        ctx.fillStyle = '#ff6666';
        ctx.font = '20px monospace';
        ctx.fillText(gameState.banReason, canvas.width / 2, canvas.height / 2 + 10);

        ctx.fillStyle = '#888';
        ctx.font = '14px monospace';
        ctx.fillText('Server-side anti-cheat detected manipulation', canvas.width / 2, canvas.height / 2 + 50);
        ctx.fillText('Refresh page to try again', canvas.width / 2, canvas.height / 2 + 75);

        ctx.textAlign = 'left';
    }

    function drawFinishScreen() {
        ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#00ff88';
        ctx.font = 'bold 48px monospace';
        ctx.textAlign = 'center';
        ctx.fillText('🏁 FINISHED! 🏁', canvas.width / 2, canvas.height / 2 - 40);

        ctx.fillStyle = '#fff';
        ctx.font = '24px monospace';
        ctx.fillText(`Time: ${(gameState.finishTime / 1000).toFixed(2)}s`, canvas.width / 2, canvas.height / 2 + 10);

        // Determine placement
        let placement = 1;
        gameState.opponents.forEach(opp => {
            if (opp.finished && opp.x >= gameState.x) placement++;
        });
        const placeStr = ['1st', '2nd', '3rd', '4th'][placement - 1] || `${placement}th`;

        ctx.fillStyle = placement === 1 ? '#ffd700' : '#ccc';
        ctx.font = 'bold 32px monospace';
        ctx.fillText(`${placeStr} Place!`, canvas.width / 2, canvas.height / 2 + 55);

        ctx.textAlign = 'left';
    }

    // --- Main Game Loop ---
    let gameLoopId = null;

    function gameLoop() {
        const now = performance.now();
        const deltaMs = now - gameState.lastFrameTime;
        gameState.lastFrameTime = now;

        // FPS counter
        gameState.frameCount++;
        if (now - gameState.fpsTimer >= 1000) {
            gameState.fps = gameState.frameCount;
            gameState.frameCount = 0;
            gameState.fpsTimer = now;
        }

        if (gameState.banned || gameState.finished) {
            render();
            return;
        }

        const dt = Math.min(deltaMs, 50) / 1000; // Cap at 50ms for stability

        // 1. Client-side prediction for responsiveness
        clientPredict(dt);

        // 2. Send input to server (with client delta - server will IGNORE it and use its own)
        gameState.inputSequence++;
        const inputPacket = {
            keys: { ...gameState.keys },
            deltaTime: deltaMs,
            timestamp: now,
            sequence: gameState.inputSequence,
            clientDistance: gameState.clientDistance
        };

        // Store for reconciliation
        gameState.pendingInputs.push({
            sequence: gameState.inputSequence,
            keys: { ...gameState.keys },
            dt: dt
        });

        // 3. Get server response (in real game this would be async/network)
        const serverResponse = ServerSimulation.receiveClientInput(PLAYER_ID, inputPacket);

        // 4. Reconcile with server state
        if (serverResponse) {
            reconcileWithServer(serverResponse);
        }

        // 5. Update opponents
        updateOpponents(dt);

        // 6. Update particles
        updateParticles(dt);

        // 7. Render
        render();

        // 8. Update status
        updateStatus(deltaMs);
    }

    function updateStatus(deltaMs) {
        const drift = Math.sqrt(
            (gameState.x - gameState.serverX) ** 2 +
            (gameState.y - gameState.serverY) ** 2
        ).toFixed(1);

        statusDiv.innerHTML = `
            <span style="color:#888">Frame Δ: ${deltaMs.toFixed(1)}ms</span> |
            <span style="color:#4ecdc4">Client-Server Drift: ${drift}px</span> |
            <span style="color:${gameState.violations > 5 ? '#ff0000' : '#00ff00'}">
                Anti-Cheat Status: ${gameState.violations === 0 ? '✅ Clean' : `⚠️ ${gameState.violations} violations`}
            </span>
        `;
    }

    // --- Start Game ---
    gameLoopId = setInterval(gameLoop, GAME_LOOP_INTERVAL);

    // Cleanup on page unload
    window.addEventListener('beforeunload', () => {
        if (gameLoopId) clearInterval(gameLoopId);
    });
})();